package be.schaubroeck.lpb.rkm.rekenmotor.rsz.werkbonus;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplNotieGepens;
import be.schaubroeck.lpb.tools.enumtypes.Hoedanigheid;
import com.google.common.collect.ImmutableSet;
import org.joda.time.LocalDate;
import org.joda.time.Years;

import java.util.Set;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;

public class WerkbonusGepensioneerdOpdracht {

    private static final Set<Hoedanigheid> HOEDANIGHEDEN_IN_AANMERKING =
            ImmutableSet.of(Hoedanigheid.TIJDELIJKEN_EN_CONTRACTUELEN, Hoedanigheid.GESUBSIDIEERDE_CONTRACTUELEN);

    public boolean komtInAanMerking(RekenContext opdrachtContext, Opdracht opdracht) {
        boolean isContractueel = HOEDANIGHEDEN_IN_AANMERKING.contains(opdracht.getHoedanigheid());
        boolean is65VoorStartOpdracht = is65VoorEersteDagMaand(opdrachtContext, opdracht);
        boolean isNotieGepensioeneerdOpStartWerkbonus = isNotieGepensioeneerdOpStartWerkbonus(opdrachtContext, opdracht);
        return isContractueel && (is65VoorStartOpdracht || isNotieGepensioeneerdOpStartWerkbonus);
    }

    public boolean is65VoorEersteDagMaand(RekenContext opdrachtContext, Opdracht opdracht) {
        RekenTijd rekenTijd = opdrachtContext.getUnchecked(REKENTIJD_KEY);
        LocalDate startDatum = rekenTijd.beginDatum;
        LocalDate geboorteDatum = opdracht.getPersoon().getGeboorteDatum();
        int leeftijd = Years.yearsBetween(geboorteDatum, startDatum.minusDays(1)).getYears();
        return leeftijd >= LeeftijdPensioen.bepaal(rekenTijd.eindDatum, geboorteDatum);
    }

    private boolean isNotieGepensioeneerdOpStartWerkbonus(RekenContext opdrachtContext, Opdracht opdracht) {
        if (opdracht.getPeriode().contains(WerkbonusGepensioneerdActief.getStartDatum())) {
            PersoonsDataManager persoonsDataManager = opdrachtContext.getUnchecked(RekenChainKey.PERSOONSDATA_MANAGER_KEY);
            LocalDate selectieDatum = WerkbonusGepensioneerdActief.getStartDatum().dayOfMonth().withMaximumValue();
            Persoon persoonOpStartWerkbonus = persoonsDataManager.getPersoonOpDatum(selectieDatum);
            Opdracht opdrachtOpStartWerkbonus = null;
            if (persoonOpStartWerkbonus != null) {
                opdrachtOpStartWerkbonus = persoonOpStartWerkbonus.getOpdrachten().stream().filter(x -> x.getId().equals(opdracht.getId())).findAny().orElse(null);
            }
            if (opdrachtOpStartWerkbonus != null) {
                Opper opperOpStartWerkbonus = RekenTools.findOpper(opdrachtOpStartWerkbonus, WerkbonusGepensioneerdActief.getStartDatum());
                return opperOpStartWerkbonus != null && opperOpStartWerkbonus.getRszppo().getNotieGepensioneerd() == DmfapplNotieGepens.GEPENSION;
            }
        }
        return false;
    }
}
